mapper.select:
select l.id, l.applicant_id, l.leave_type_id, l.start_time, l.end_time, l.days, l.reason, l.status, l.hr_comment, l.boss_comment, l.hr_approved_at, l.boss_approved_at, l.created_at, l.updated_at, t.name as leaveTypeName, e.real_name as applicantName from leave_request l left join leave_type t on l.leave_type_id = t.id left join user e on l.applicant_id = e.id
and t.name like concat('%',#{pageDTO.leaveTypeName},'%')
and l.commit_date = #{pageDTO.commitDate}
